import markdown
import weasyprint

with open('public-apis-research.md', 'r', encoding='utf-8') as f:
    content = f.read()

html_content = markdown.markdown(content, extensions=['tables', 'fenced_code'])

css = '''
body { font-family: Arial, Microsoft YaHei, sans-serif; margin: 40px; line-height: 1.8; color: #222; }
h1 { color: #1a1a2e; border-bottom: 3px solid #1a1a2e; padding-bottom: 10px; font-size: 28px; }
h2 { color: #16213e; border-bottom: 2px solid #e94560; padding-bottom: 6px; font-size: 22px; margin-top: 35px; }
h3 { color: #0f3460; font-size: 18px; margin-top: 25px; }
table { border-collapse: collapse; width: 100%; margin: 15px 0; font-size: 13px; }
th { background: #1a1a2e; color: white; padding: 8px 10px; text-align: left; }
td { padding: 6px 10px; border-bottom: 1px solid #ddd; }
tr:nth-child(even) { background: #f9f9f9; }
code { background: #f4f4f4; padding: 2px 6px; border-radius: 3px; font-size: 13px; color: #c7254e; }
blockquote { border-left: 4px solid #e94560; margin: 15px 0; padding: 10px 15px; background: #fafafa; font-style: italic; }
ul { padding-left: 20px; }
li { margin-bottom: 5px; }
a { color: #1a0dab; text-decoration: none; }
strong { color: #333; }
hr { border: none; border-top: 1px solid #ddd; margin: 30px 0; }
'''

full_html = f'''<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8">
<title>Public APIs 项目深度调研报告</title>
<style>{css}</style>
</head>
<body>
{html_content}
</body>
</html>'''

with open('public-apis-research.html', 'w', encoding='utf-8') as f:
    f.write(full_html)

print("HTML generated, converting to PDF...")
weasyprint.HTML(filename='public-apis-research.html').write_pdf('public-apis-research.pdf')
print("PDF generated: public-apis-research.pdf")

